#!/bin/bash\n# FreeAutotune Build Script for macOS\n\nset -e\n\necho \"🎵 FreeAutotune Build Script\"\necho \"=============================\"\necho \"\"\n\n# Check if JUCE submodule exists\nif [ ! -d \"JUCE\" ]; then\n    echo \"📦 Adding JUCE submodule...\"\n    git submodule add https://github.com/juce-framework/JUCE.git\nfi\n\n# Create build directory\nif [ ! -d \"build\" ]; then\n    mkdir build\nfi\n\ncd build\n\necho \"🔨 Generating build files...\"\nif [[ $(uname -m) == 'arm64' ]]; then\n    # Apple Silicon\n    cmake -GXcode -DCMAKE_OSX_ARCHITECTURES=arm64 ..\nelse\n    # Intel\n    cmake -GXcode ..\nfi\n\necho \"🔨 Building FreeAutotune...\"\ncmake --build . --config Release\n\necho \"\"\necho \"✅ Build complete!\"\necho \"\"\necho \"Plugin locations:\"\necho \"  • AU: ./FreeAutotune_artefacts/Release/AU/\"\necho \"  • VST3: ./FreeAutotune_artefacts/Release/VST3/\"\necho \"\"\necho \"To install:\"\necho \"  • macOS AU: cp -r FreeAutotune_artefacts/Release/AU/FreeAutotune.component ~/Library/Audio/Plug-Ins/Components/\"\necho \"  • macOS VST3: cp -r FreeAutotune_artefacts/Release/VST3/FreeAutotune.vst3 ~/Library/Audio/Plug-Ins/VST3/\"\n"